  ('fire-eq-eng-moex-00213', 'fire-eq-eng', 'fire-eq-eng-moex-114-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依原有合法建築物公共安全改善辦法，有關原有合法建築物之層間區劃改善規定，防火構造 建築物之樓地板應為連續完整面，並應突出建築物外牆A公分以上；與樓地板交接處之外牆 或外牆之內側面高度有 B 公分以上，且該外牆或內側構造具有與樓地板同等以上防火時效 者，得免突出。下列A與B何者正確？', '["A=50，B=100", "A=50，B=90", "A=60，B=100", "A=60，B=90"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:13+00:00", "source_pdf_sha1": "60003cfa7dbf", "answer_pdf_sha1": "4490a7f85367", "source_family": "moex-gov-tw", "moex": {"exam_code": "114050", "c": "401", "s": "0802", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "114", "exam_name": "114年專技人員高等考試大地工程技師考試分階段考試(第一階段考試)、驗船師、引水人、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通...", "original_question_number": 37, "answer_corrected": false, "flags": [], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
